1	import { AssetInstanceStatus } from "@prisma/client";
2	import type { Prisma } from "@prisma/client";
3	
4	const allowedTransitionsMap: Record<AssetInstanceStatus, AssetInstanceStatus[]> = {
5	  IN_STOCK: ["AVAILABLE"],
6	  AVAILABLE: ["ASSIGNED", "LOST"],
7	  ASSIGNED: ["IN_USE", "AVAILABLE", "LOST"],
8	  IN_USE: ["RETURNING", "REPAIRING", "TRANSFERRING", "LOST"],
9	  RETURNING: ["AVAILABLE", "SCRAPPED"],
10	  REPAIRING: ["IN_USE", "AVAILABLE", "SCRAPPED"],
11	  TRANSFERRING: ["IN_USE"],
12	  LOST: [],
13	  SCRAPPED: [],
14	};
15	
16	export class TransitionError extends Error {
17	  constructor(message: string) {
18	    super(message);
19	    this.name = "TransitionError";
20	  }
21	}
22	
23	/** HMR-safe check: instanceof can fail after Turbopack hot reload */
24	export function isTransitionError(e: unknown): e is TransitionError {
25	  return e instanceof TransitionError || (e as Error)?.name === "TransitionError";
26	}
27	
28	export class AssetStateMachine {
29	  static allowedTransitions = new Map(
30	    Object.entries(allowedTransitionsMap),
31	  ) as Map<AssetInstanceStatus, AssetInstanceStatus[]>;
32	
33	  static canTransition(
34	    from: AssetInstanceStatus,
35	    to: AssetInstanceStatus,
36	  ): boolean {
37	    const allowed = allowedTransitionsMap[from];
38	    return allowed?.includes(to) ?? false;
39	  }
40	
41	  static async transition(
42	    tx: Prisma.TransactionClient,
43	    assetId: string,
44	    to: AssetInstanceStatus,
45	    context: {
46	      operatorId: string;
47	      lostReason?: string;
48	      scrapReason?: string;
49	    },
50	  ): Promise<{
51	    asset: Record<string, unknown>;
52	    before: Record<string, unknown>;
53	    after: Record<string, unknown>;
54	    cancelledTicketIds: string[];
55	  }> {
56	    const asset = await tx.assetInstance.findUnique({
57	      where: { id: assetId },
58	    });
59	
60	    if (!asset) {
61	      throw new TransitionError("Asset not found");
62	    }
63	
64	    const from = asset.status;
65	
66	    if (!AssetStateMachine.canTransition(from, to)) {
67	      throw new TransitionError(
68	        `Cannot transition asset from ${from} to ${to}`,
69	      );
70	    }
71	
72	    const before = { ...asset };
73	    let cancelledTicketIds: string[] = [];
74	
75	    if (to === "LOST") {
76	      const activeTickets = await tx.ticket.findMany({
77	        where: {
78	          targetAssetId: assetId,
79	          status: { notIn: ["COMPLETED", "CANCELLED", "REJECTED"] },
80	        },
81	      });
82	      cancelledTicketIds = activeTickets.map((t) => t.id);
83	      if (cancelledTicketIds.length > 0) {
84	        await tx.ticket.updateMany({
85	          where: { id: { in: cancelledTicketIds } },
86	          data: { status: "CANCELLED" },
87	        });
88	      }
89	    }
90	
91	    const updateData: Record<string, unknown> = { status: to };
92	
93	    if (to === "LOST" && context.lostReason) {
94	      updateData.lostReason = context.lostReason;
95	    }
96	    if (to === "SCRAPPED") {
97	      if (context.scrapReason) {
98	        updateData.scrapReason = context.scrapReason;
99	      }
100	      updateData.holderId = null;
101	    }
102	    if (to === "AVAILABLE") {
103	      updateData.holderId = null;
104	    }
105	
106	    const updated = await tx.assetInstance.update({
107	      where: { id: assetId },
108	      data: updateData as Prisma.AssetInstanceUpdateInput,
109	    });
110	
111	    return {
112	      asset: updated as unknown as Record<string, unknown>,
113	      before,
114	      after: updated as unknown as Record<string, unknown>,
115	      cancelledTicketIds,
116	    };
117	  }
118	}
