1	import { TicketType, TicketStatus, AssetInstanceStatus } from "@prisma/client";
2	import type { Prisma } from "@prisma/client";
3	
4	// Allowed transitions indexed by (ticketType, fromStatus)
5	const transitionsByTypeAndStatus: Record<
6	  string,
7	  Record<string, TicketStatus[]>
8	> = {
9	  APPLY: {
10	    SUBMITTED: ["PENDING_MANAGER_1", "PENDING_IT"],
11	    PENDING_MANAGER_1: ["PENDING_IT", "REJECTED", "CANCELLED"],
12	    PENDING_IT: ["APPROVED", "IN_PROGRESS", "REJECTED", "CANCELLED"],
13	    APPROVED: ["IN_PROGRESS", "REJECTED", "CANCELLED"],
14	    IN_PROGRESS: ["COMPLETED", "CANCELLED"],
15	    REJECTED: [],
16	    CANCELLED: [],
17	    COMPLETED: [],
18	  },
19	  RETURN: {
20	    SUBMITTED: ["PENDING_IT"],
21	    PENDING_IT: ["APPROVED", "IN_PROGRESS", "REJECTED", "CANCELLED"],
22	    APPROVED: ["IN_PROGRESS", "REJECTED", "CANCELLED"],
23	    IN_PROGRESS: ["COMPLETED", "CANCELLED"],
24	    REJECTED: [],
25	    CANCELLED: [],
26	    COMPLETED: [],
27	  },
28	  REPAIR: {
29	    SUBMITTED: ["PENDING_IT"],
30	    PENDING_IT: ["APPROVED", "IN_PROGRESS", "REJECTED", "CANCELLED"],
31	    APPROVED: ["IN_PROGRESS", "REJECTED", "CANCELLED"],
32	    IN_PROGRESS: ["COMPLETED", "CANCELLED"],
33	    REJECTED: [],
34	    CANCELLED: [],
35	    COMPLETED: [],
36	  },
37	  TRANSFER: {
38	    SUBMITTED: ["PENDING_MANAGER_1", "PENDING_MANAGER_2"],
39	    PENDING_MANAGER_1: ["PENDING_MANAGER_2", "REJECTED", "CANCELLED"],
40	    PENDING_MANAGER_2: ["PENDING_IT", "REJECTED", "CANCELLED"],
41	    PENDING_IT: ["APPROVED", "IN_PROGRESS", "REJECTED", "CANCELLED"],
42	    APPROVED: ["IN_PROGRESS", "REJECTED", "CANCELLED"],
43	    IN_PROGRESS: ["COMPLETED", "CANCELLED"],
44	    REJECTED: [],
45	    CANCELLED: [],
46	    COMPLETED: [],
47	  },
48	};
