50	export class WorkflowError extends Error {
51	  constructor(message: string) {
52	    super(message);
53	    this.name = "WorkflowError";
54	  }
55	}
56	
57	/** HMR-safe check: instanceof can fail after Turbopack hot reload */
58	export function isWorkflowError(e: unknown): e is WorkflowError {
59	  return e instanceof WorkflowError || (e as Error)?.name === "WorkflowError";
60	}
