62	export class TicketWorkflow {
63	  static allowed = new Map<
64	    TicketType,
65	    Map<TicketStatus, TicketStatus[]>
66	  >();
67	
68	  private static ensureAllowed(): void {
69	    if (TicketWorkflow.allowed.size === 0) {
70	      for (const [type, transitions] of Object.entries(
71	        transitionsByTypeAndStatus,
72	      )) {
73	        const inner = new Map<TicketStatus, TicketStatus[]>();
74	        for (const [from, toList] of Object.entries(transitions)) {
75	          inner.set(from as TicketStatus, toList as TicketStatus[]);
76	        }
77	        TicketWorkflow.allowed.set(type as TicketType, inner);
78	      }
79	    }
80	  }
81	
82	  static canTransition(
83	    type: TicketType,
84	    from: TicketStatus,
85	    to: TicketStatus,
86	  ): boolean {
87	    TicketWorkflow.ensureAllowed();
88	    const byType = transitionsByTypeAndStatus[type];
89	    if (!byType) return false;
90	    const allowed = byType[from];
91	    return allowed?.includes(to) ?? false;
92	  }
93	
94	  /**
95	   * Determine the next status when a ticket is approved.
96	   */
97	  static nextOnApprove(
98	    type: TicketType,
99	    currentStatus: TicketStatus,
100	  ): TicketStatus | null {
101	    if (type === "TRANSFER" && currentStatus === "PENDING_MANAGER_1") {
102	      return "PENDING_MANAGER_2";
103	    }
104	    if (
105	      currentStatus === "PENDING_MANAGER_1" ||
106	      currentStatus === "PENDING_MANAGER_2"
107	    ) {
108	      return "PENDING_IT";
109	    }
110	    if (currentStatus === "PENDING_IT") {
111	      return "APPROVED";
112	    }
113	    return null;
114	  }
115	
116	  /**
117	   * Determine the initial status for a newly submitted ticket.
118	   */
119	  static determineInitialStatus(
120	    type: TicketType,
121	    context: {
122	      isManager: boolean;
123	      purchasePrice?: number;
124	      hasFromHolder?: boolean;
125	    },
126	  ): TicketStatus {
127	    switch (type) {
128	      case "APPLY": {
129	        // Purchase price < 1000: skip manager, direct PENDING_IT
130	        if (context.purchasePrice !== undefined && context.purchasePrice < 1000) {
131	          return "PENDING_IT";
132	        }
133	        // MANAGER applying for themselves: PENDING_IT
134	        if (context.isManager) {
135	          return "PENDING_IT";
136	        }
137	        return "PENDING_MANAGER_1";
138	      }
139	      case "RETURN":
140	      case "REPAIR":
141	        return "PENDING_IT";
142	      case "TRANSFER":
143	        // No fromHolderId: skip PENDING_MANAGER_1
144	        if (!context.hasFromHolder) {
145	          return "PENDING_MANAGER_2";
146	        }
147	        return "PENDING_MANAGER_1";
148	      default:
149	        return "PENDING_IT";
150	    }
151	  }
152	
153	  /**
154	   * Same as nextOnApprove — returns the target status when approved.
155	   */
156	  static getApproveTarget(
157	    type: TicketType,
158	    currentStatus: TicketStatus,
159	  ): TicketStatus | null {
160	    return TicketWorkflow.nextOnApprove(type, currentStatus);
161	  }
162	
163	  static async applyTransition(
164	    tx: Prisma.TransactionClient,
165	    ticketId: string,
166	    toStatus: TicketStatus,
167	    context: {
168	      operatorId: string;
169	      rejectReason?: string;
170	      deputy?: boolean;
171	      deputyApproverId?: string;
172	      repairOutcome?: "return_holder" | "make_available" | "scrap";
173	      assetStatusOnComplete?: AssetInstanceStatus;
174	      completedAt?: Date;
175	    },
176	  ): Promise<{
177	    ticket: Record<string, unknown>;
178	    beforeStatus: TicketStatus;
179	    afterStatus: TicketStatus;
180	    assetChanges: Record<string, unknown>[];
181	  }> {
182	    const ticket = await tx.ticket.findUnique({
183	      where: { id: ticketId },
184	    });
185	
186	    if (!ticket) {
187	      throw new WorkflowError("Ticket not found");
188	    }
189	
190	    const beforeStatus = ticket.status as TicketStatus;
191	
192	    if (
193	      toStatus !== "REJECTED" &&
194	      toStatus !== "CANCELLED" &&
195	      !TicketWorkflow.canTransition(
196	        ticket.type as TicketType,
197	        beforeStatus,
198	        toStatus,
199	      )
200	    ) {
201	      throw new WorkflowError(
202	        `Cannot transition ${ticket.type} ticket from ${beforeStatus} to ${toStatus}`,
203	      );
204	    }
205	
206	    // Allow REJECTED/CANCELLED from any non-terminal status
207	    if (
208	      (toStatus === "REJECTED" || toStatus === "CANCELLED") &&
209	      ["COMPLETED", "REJECTED", "CANCELLED"].includes(beforeStatus)
210	    ) {
211	      throw new WorkflowError(
212	        `Cannot ${toStatus.toLowerCase()} a ticket in ${beforeStatus} status`,
213	      );
214	    }
215	
216	    const updateData: Record<string, unknown> = {
217	      status: toStatus,
218	    };
219	
220	    const assetChanges: Record<string, unknown>[] = [];
221	
222	    if (toStatus === "REJECTED" && context.rejectReason) {
223	      updateData.rejectReason = context.rejectReason;
224	    }
225	
226	    if (toStatus === "COMPLETED") {
227	      updateData.completedAt = context.completedAt ?? new Date();
228	    }
229	
230	    if (context.deputy && context.deputyApproverId) {
231	      updateData.deputyApproval = true;
232	      updateData.deputyApproverId = context.deputyApproverId;
233	    }
234	
235	    const updated = await tx.ticket.update({
236	      where: { id: ticketId },
237	      data: updateData as Prisma.TicketUpdateInput,
238	      include: {
239	        targetAsset: true,
240	      },
241	    });
242	
243	    // Handle asset changes on COMPLETED
244	    if (toStatus === "COMPLETED" && updated.targetAsset) {
245	      if (ticket.type === "APPLY") {
246	        const updatedAsset = await tx.assetInstance.update({
247	          where: { id: updated.targetAsset.id },
248	          data: {
249	            status: "IN_USE",
250	            holderId: ticket.applicantId,
251	          },
252	        });
253	        assetChanges.push(
254	          updatedAsset as unknown as Record<string, unknown>,
255	        );
256	      } else if (ticket.type === "RETURN") {
257	        const updatedAsset = await tx.assetInstance.update({
258	          where: { id: updated.targetAsset.id },
259	          data: {
260	            status: "AVAILABLE",
261	            holderId: null,
262	          },
263	        });
264	        assetChanges.push(
265	          updatedAsset as unknown as Record<string, unknown>,
266	        );
267	      } else if (ticket.type === "TRANSFER") {
268	        const updatedAsset = await tx.assetInstance.update({
269	          where: { id: updated.targetAsset.id },
270	          data: {
271	            status: "IN_USE",
272	            holderId: ticket.toHolderId,
273	            deptId: ticket.targetDeptId ?? undefined,
274	          },
275	        });
276	        assetChanges.push(
277	          updatedAsset as unknown as Record<string, unknown>,
278	        );
279	      } else if (ticket.type === "REPAIR") {
280	        // Repair completion outcome is handled by complete route context
281	        if (context.repairOutcome) {
282	          let assetUpdate: Record<string, unknown> = {
283	            status: "IN_USE",
284	          };
285	          if (context.repairOutcome === "make_available") {
286	            assetUpdate = {
287	              status: "AVAILABLE",
288	              holderId: null,
289	            };
290	          } else if (context.repairOutcome === "scrap") {
291	            assetUpdate = {
292	              status: "SCRAPPED",
293	              holderId: null,
294	            };
295	          }
296	          const updatedAsset = await tx.assetInstance.update({
297	            where: { id: updated.targetAsset.id },
298	            data: assetUpdate as Prisma.AssetInstanceUpdateInput,
299	          });
300	          assetChanges.push(
301	            updatedAsset as unknown as Record<string, unknown>,
302	          );
303	        }
304	      }
305	    }
306	
307	    return {
308	      ticket: updated as unknown as Record<string, unknown>,
309	      beforeStatus,
310	      afterStatus: toStatus,
311	      assetChanges,
312	    };
313	  }
314	}
