8	export async function POST(request: NextRequest) {
9	  try {
10	    const user = await verifyAuth(request);
11	    requireOneOf(user, "EMPLOYEE", "MANAGER");
12	
13	    const body = await request.json();
14	    const { modelId, reason, targetDeptId } = body;
15	
16	    if (!modelId || !reason) {
17	      return Response.json(
18	        { error: "modelId and reason are required" },
19	        { status: 400 },
20	      );
21	    }
22	
23	    const result = await prisma.$transaction(async (tx) => {
24	      const model = await tx.assetModel.findUnique({ where: { id: modelId } });
25	      if (!model) {
26	        throw new WorkflowError("Asset model not found");
27	      }
28	
29	      const initialStatus = TicketWorkflow.determineInitialStatus("APPLY", {
30	        isManager: user.role === "MANAGER",
31	        purchasePrice: Number(model.purchasePrice),
32	      });
33	
34	      const ticket = await tx.ticket.create({
35	        data: {
36	          type: "APPLY",
37	          status: initialStatus,
38	          applicantId: user.userId,
39	          targetModelId: modelId,
40	          reason,
41	          targetDeptId: targetDeptId ?? null,
42	        },
43	      });
44	
45	      await logTicketStatusChange(tx, {
46	        ticketId: ticket.id,
47	        operatorId: user.userId,
48	        fromStatus: "SUBMITTED",
49	        toStatus: initialStatus,
50	        metadata: { modelId, purchasePrice: Number(model.purchasePrice) },
51	      });
52	
53	      // Notify department manager if pending manager approval
54	      if (initialStatus === "PENDING_MANAGER_1") {
55	        const dept = await tx.department.findUnique({
56	          where: { id: user.deptId },
57	          include: { manager: true },
58	        });
59	        if (dept?.manager) {
60	          await notifyApprovalRequest(tx, {
61	            managerId: dept.manager.id,
62	            ticketId: ticket.id,
63	            applicantName: "",
64	            ticketType: "APPLY",
65	          });
66	        }
67	      }
68	
69	      return ticket;
70	    });
71	
72	    return Response.json(result, { status: 201 });
73	  } catch (e) {
74	    if (e instanceof AuthError) {
75	      return Response.json({ error: e.message }, { status: e.statusCode });
76	    }
77	    if (e instanceof WorkflowError) {
78	      return Response.json({ error: e.message }, { status: 400 });
79	    }
80	    return Response.json({ error: "Internal server error" }, { status: 500 });
81	  }
82	}
