6	import { logAssetStatusChange, logTicketStatusChange } from "@/lib/audit";
7	
8	export async function POST(
9	  request: NextRequest,
10	  { params }: { params: Promise<{ id: string }> },
11	) {
12	  try {
13	    const user = await verifyAuth(request);
14	
15	    const { id } = await params;
16	
17	    const result = await prisma.$transaction(async (tx) => {
18	      const ticket = await tx.ticket.findUnique({
19	        where: { id },
20	        include: { targetAsset: true },
21	      });
22	      if (!ticket) {
23	        throw new WorkflowError("Ticket not found");
24	      }
25	
26	      const currentStatus = ticket.status as import("@prisma/client").TicketStatus;
27	
28	      // Only applicant or IT_ADMIN can cancel
29	      if (ticket.applicantId !== user.userId && user.role !== "IT_ADMIN") {
30	        throw new WorkflowError("Only the applicant or IT admin can cancel this ticket");
31	      }
32	
33	      // Cannot cancel terminal tickets
34	      if (["COMPLETED", "REJECTED", "CANCELLED"].includes(currentStatus)) {
35	        throw new WorkflowError(
36	          `Cannot cancel a ticket in ${currentStatus} status`,
37	        );
38	      }
39	
40	      // Recover asset status if applicable
41	      const assetChanges: Record<string, unknown>[] = [];
42	      if (ticket.targetAsset) {
43	        const assetStatus = ticket.targetAsset.status;
44	        const ticketType = ticket.type as import("@prisma/client").TicketType;
45	
46	        // Determine recovery status based on current asset status
47	        if (
48	          (ticketType === "RETURN" && assetStatus === "RETURNING") ||
49	          (ticketType === "REPAIR" && assetStatus === "REPAIRING")
50	        ) {
51	          let recoveryStatus: import("@prisma/client").AssetInstanceStatus = "AVAILABLE";
52	          if (ticket.fromHolderId) {
53	            recoveryStatus = "IN_USE";
54	          }
55	          // For repair, recover to IN_USE if the asset was previously held
56	          if (ticketType === "REPAIR" && ticket.fromHolderId) {
57	            recoveryStatus = "IN_USE";
58	          }
59	          // For return, recover to IN_USE if held
60	          if (ticketType === "RETURN" && ticket.fromHolderId) {
61	            recoveryStatus = "IN_USE";
62	          }
63	
64	          const transition = await AssetStateMachine.transition(
65	            tx,
66	            ticket.targetAsset.id,
67	            recoveryStatus,
68	            { operatorId: user.userId },
69	          );
70	
71	          // Set holder back if recovering to IN_USE
72	          if (recoveryStatus === "IN_USE" && ticket.fromHolderId) {
73	            await tx.assetInstance.update({
74	              where: { id: ticket.targetAsset.id },
75	              data: { holderId: ticket.fromHolderId },
76	            });
77	          }
78	
79	          assetChanges.push(transition.after);
80	          await logAssetStatusChange(tx, {
81	            assetId: ticket.targetAsset.id,
82	            operatorId: user.userId,
83	            fromStatus: assetStatus,
84	            toStatus: recoveryStatus,
85	            metadata: { ticketId: id, reason: "cancelled" },
86	          });
87	        } else if (ticketType === "TRANSFER" && assetStatus === "TRANSFERRING") {
88	          const transition = await AssetStateMachine.transition(
89	            tx,
90	            ticket.targetAsset.id,
91	            "IN_USE",
92	            { operatorId: user.userId },
93	          );
94	          assetChanges.push(transition.after);
95	          await logAssetStatusChange(tx, {
96	            assetId: ticket.targetAsset.id,
97	            operatorId: user.userId,
98	            fromStatus: "TRANSFERRING",
99	            toStatus: "IN_USE",
100	            metadata: { ticketId: id, reason: "cancelled" },
101	          });
102	        }
103	      }
104	
105	      const updated = await tx.ticket.update({
106	        where: { id },
107	        data: { status: "CANCELLED" },
108	      });
109	
110	      await logTicketStatusChange(tx, {
111	        ticketId: id,
112	        operatorId: user.userId,
113	        fromStatus: currentStatus,
114	        toStatus: "CANCELLED",
115	      });
116	
117	      return { ticket: updated, assetChanges };
118	    });
119	
120	    return Response.json(result);
121	  } catch (e) {
122	    if (e instanceof AuthError) {
123	      return Response.json({ error: e.message }, { status: e.statusCode });
124	    }
125	    if (e instanceof WorkflowError || e instanceof TransitionError) {
126	      return Response.json({ error: e.message }, { status: 400 });
127	    }
128	    return Response.json({ error: "Internal server error" }, { status: 500 });
129	  }
130	}
